def cds_translator(seq):
    amino_list = ['F','F',\
                  'L','L','L','L','L','L',\
                  'S','S','S','S','S','S',\
                  'Y','Y',\
                  '*','*',\
                  'C','C',\
                  '*',\
                  'W',\
                  'P','P','P','P',\
                  'H','H',\
                  'Q','Q',\
                  'R','R','R','R','R','R',\
                  'I','I','I',\
                  'M',\
                  'T','T','T','T',\
                  'N','N',\
                  'K','K',\
                  'V','V','V','V',\
                  'A','A','A','A',\
                  'D','D',\
                  'E','E',\
                  'G','G','G','G']
    amino_set = list(sorted(set(amino_list)))
    # print(amino_set)
    codon_table1 = ['ttt', 'ttc',\
                    'tta', 'ttg','ctt', 'ctc', 'cta', 'ctg',\
                    'tct', 'tcc', 'tca', 'tcg', 'agt', 'agc',\
                    'tat', 'tac',\
                    'taa', 'tag',\
                    'tgt', 'tgc',\
                    'tga',\
                    'tgg',\
                    'cct', 'ccc', 'cca', 'ccg',\
                    'cat', 'cac',\
                    'caa', 'cag',\
                    'cgt', 'cgc', 'cga', 'cgg','aga', 'agg',\
                    'att', 'atc', 'ata',\
                    'atg',\
                    'act', 'acc', 'aca', 'acg',\
                    'aat', 'aac',\
                    'aaa', 'aag',\
                    'gtt', 'gtc', 'gta', 'gtg',\
                    'gct', 'gcc', 'gca', 'gcg',\
                    'gat', 'gac',\
                    'gaa', 'gag',\
                    'ggt', 'ggc', 'gga', 'ggg']

    # print (len(amino_list))
    # print (len(codon_table1))
    codon_dict = dict(zip(codon_table1, amino_list))
    # print (codon_dict)
    seqlen = len(seq)
    if seqlen % 3 != 0:
        return 'It is not a cds sequence!'
    else:
        seq = seq.lower()
        Protein = ''
        for codon_i in range(0,seqlen,3):
            codon = seq[codon_i:codon_i+3]
            if codon in codon_table1:
                Protein = Protein+codon_dict[codon]
            else:
                Protein = Protein+'~'
    return Protein


